{
var seed = GetInt(parameters, "seed", context.Seed);
var cut = GetChoice(parameters, "cutShape", "round");
var size = GetFloat(parameters, "size", 0.6f);
var gemColor = GetColor(parameters, "gemColor", Color.FromRgb(60, 120, 240));
var specColor = GetColor(parameters, "specColor", Color.FromRgb(180, 220, 255));
var gloss = GetFloat(parameters, "gloss", 0.7f);

var tileSize = context.TileSize;
var buffer = new PixelBuffer(tileSize, tileSize);

var gR = gemColor.R / 255f; var gG = gemColor.G / 255f; var gB = gemColor.B / 255f;
var sR = specColor.R / 255f; var sG = specColor.G / 255f; var sB = specColor.B / 255f;

var halfSize = tileSize * 0.5f;
var radius = halfSize * size;

buffer.ParallelForEachPixel((x, y) =>
{
    var px = x + 0.5f - halfSize;
    var py = y + 0.5f - halfSize;

    // Distance function based on cut shape
    var dist = cut switch
    {
        "square" => MathF.Max(MathF.Abs(px), MathF.Abs(py)),
        "diamond" => (MathF.Abs(px) + MathF.Abs(py)) * 0.7071f,
        "teardrop" => MathF.Sqrt(px * px + (py - radius * 0.2f) * (py - radius * 0.2f)) * (1f - py / (radius * 2f) * 0.3f),
        _ => MathF.Sqrt(px * px + py * py)
    };

    var alpha = 1f - SmoothStep(radius * 0.8f, radius, dist);
    if (alpha <= 0.01f)
    {
        buffer.SetPixel(x, y, 0, 0, 0, 0);
        return;
    }

    // Facet-like internal pattern using deterministic cell noise
    var cellSize = radius * 0.3f;
    var cellX = (int)MathF.Floor(px / cellSize + 0.5f);
    var cellY = (int)MathF.Floor(py / cellSize + 0.5f);
    var cellHash = HashToUnit(cellX, cellY, seed);

    // Each facet has slightly different brightness
    var facetBrightness = 0.7f + cellHash * 0.3f;

    // Center highlight: bright reflection in the upper-left
    var hlX = -radius * 0.25f;
    var hlY = -radius * 0.25f;
    var hlDist = MathF.Sqrt((px - hlX) * (px - hlX) + (py - hlY) * (py - hlY));
    var highlight = MathF.Exp(-hlDist * hlDist / (radius * radius * 0.15f)) * gloss;

    // Secondary highlight (smaller, lower-right)
    var hl2X = radius * 0.3f;
    var hl2Y = radius * 0.3f;
    var hlDist2 = MathF.Sqrt((px - hl2X) * (px - hl2X) + (py - hl2Y) * (py - hl2Y));
    var highlight2 = MathF.Exp(-hlDist2 * hlDist2 / (radius * radius * 0.08f)) * gloss * 0.5f;

    // Edge darkening
    var edgeDark = Math.Clamp(1f - (radius - dist) / (radius * 0.2f), 0f, 1f) * 0.3f;

    // Combine: base gem color * facet brightness + specular highlights - edge darkening
    var finalR = gR * facetBrightness + sR * Math.Max(highlight, highlight2) - edgeDark * gR;
    var finalG = gG * facetBrightness + sG * Math.Max(highlight, highlight2) - edgeDark * gG;
    var finalB = gB * facetBrightness + sB * Math.Max(highlight, highlight2) - edgeDark * gB;

    buffer.SetPixel(x, y,
        Math.Clamp(finalR, 0f, 1f),
        Math.Clamp(finalG, 0f, 1f),
        Math.Clamp(finalB, 0f, 1f), alpha);
});

return buffer;
}
